function.body:
pRecordID VARCHAR2(32);
	pMessage VARCHAR2(2000);
	pDocAction VARCHAR2(60);
	pUserID VARCHAR2(32);
	pResult NUMBER;
	vParams RECORD;
	vOrder RECORD;
	vInOut RECORD;
BEGIN

	FOR vParams IN (
		SELECT *
		FROM ad_ep_instance_para
		WHERE ad_ep_instance_id = pInstance
	) LOOP
		IF (vParams.parametername LIKE 'DocAction') THEN
			pDocAction := vParams.p_string;
		ELSIF (vParams.parametername LIKE 'Record_ID') THEN
			pRecordID := vParams.p_string;
		ELSIF (vParams.parametername LIKE 'User') THEN
			pUserID := vParams.p_string;
		ELSIF (vParams.parametername LIKE 'Message') THEN
			pMessage := vParams.p_text;
		ELSIF (vParams.parametername LIKE 'Result') THEN
			pResult := vParams.p_number;
		END IF;
	END LOOP;

	--Repuramos el albaran
 	SELECT * INTO vInOut FROM m_inout WHERE m_inout_id=pRecordID AND docstatus='DR' and issotrx='N';
	IF vInOut.m_inout_id IS NULL THEN
		RETURN;
	END IF;

	--Repuramos el pedido de compra
 	SELECT * INTO vOrder FROM c_order WHERE c_order_id=vInOut.c_order_id AND docstatus='CO';
	IF vOrder.c_order_id IS NULL THEN
		RETURN;
	END IF;

	--Actualizamos el albaran
	UPDATE m_inout SET c_campaign_id=vOrder.c_campaign_id
	WHERE m_inout_id=pRecordID;
END SSIMACC_SETCOMPAING
